"""A pole is attached by an un-actuated joint to a cart, which moves along a frictionless track. The pendulum is placed upright on the cart and the goal is to balance the pole by applying forces in the left and right direction on the cart.

The episode ends if:

The pole Angle is greater than ±12°
The Cart Position is greater than ±2.4
The episode length is greater than 500

We get a reward of +1 every timestep that the Pole stays in the equilibrium.
"""

import gym
import numpy as np
np.bool8 = np.bool_

device="cuda" if torch.cuda.is_cuda_available() else "cpu"

env=gym.make("CartPole-v1")
eval_env=gym.make("CartPole-v1")

obs_space=env.observation_space
act_space=env.action_space

obs_space,act_space

"""Obs space is a two arrays matrix, first is for minimum values and second is for the maximum ones.
- 0th is Cart position
- 1st is cart velocity (-inf to +inf)
- 2nd is Pole angle (roughly +-24°)
- 3rd is Pole's angular velocity (-inf to +inf)

Act space instead is either go one unit right or one unit left

Willing to apply a Reinforce Policy we use a simple MLP that, given the state, outputs the best action to minimize loss. We'll define loss later.
"""

import torch
import torch.nn as nn
from torch.distributions import Categorical
from torch import optim

class Policy(nn.Module):
  def __init__(self,state_size,action_size,hidden_size) -> None:
    super().__init__()

    self.MLP=nn.Sequential(
        nn.Linear(state_size,hidden_size),
        nn.ReLU(),
        nn.Linear(hidden_size,action_size),
        nn.Softmax(dim=1)
    )

  def forward(self,x):
    return self.MLP(x)

  def act(self,state):
    state=torch.from_numpy(state).float().unsqueeze(0).to('cuda') #we convert state's numpy array to torch tensor, ensuring they're floats and one dimensional.
    probs=self.forward(state)
    m=Categorical(probs) #we take softmax output and prepare the policy
    action=m.sample() #we choose the action by sampling from the softmax output distribution
    return action.item(), m.log_prob(action) #pick the action decided by policy and return it among its ln

"""![image.png](data:image/png;base64,)

Now we define our Reinforce algorithm (which is nothing but a Monte Carlo Policy Gradient approach):
"""

from collections import deque

def reinforce(policy,optimizer,n_episodes,max_t,gamma,print_every):
  """ Policy is the nn we defined before,
      Max_t is the number of steps per episode
      Gamma is the discount factor """

  score_deque=deque(maxlen=100)
  scores=[]

  for i in range(1,n_episodes+1):

    log_probs=[]
    rewards=[]
    state=env.reset()
    for t in range(max_t): #we play a full episode and sum all the rewards
      action,log_prob=policy.act(state)
      log_probs.append(log_prob)
      state,reward,done,_=env.step(action) #env.step 4th variable is just info data
      rewards.append(reward)

      if done:
        break
    score_deque.append(sum(rewards))
    scores.append(sum(rewards))

    returns=deque(maxlen=max_t)
    n_steps=len(rewards)
    for t in range(n_steps)[::-1]: #compute cumulative discounted return (G_t) for every step. We proceed backwards, optimizing computations (if not backwards we'd have to compute the product of squared discount factors from t to the end for every step t. In this way we add only two "rewards" per step.)
      discounted_return_t=returns[0] if len(returns)>0 else 0
      returns.appendleft(gamma*discounted_return_t+rewards[t])

    epsilon=np.finfo(np.float32).eps.item() #a small epsilon to avoid zero division
    returns=torch.tensor(returns)
    returns=(returns-returns.mean())/((returns.std())+epsilon) #standardize returns for more stable training

    policy_loss=[]
    for log_prob,disc_return in zip(log_probs, returns):
      policy_loss.append(-log_prob*disc_return) #put  a "-" to use gradient descent. Equivalent to maximize discounted return
    policy_loss=torch.cat(policy_loss).sum()

    optimizer.zero_grad()
    policy_loss.backward()
    optimizer.step()

    if i%print_every==0:
      print(f"Episode {i} \t Avg Score: {np.mean(score_deque):.2f}")
  return scores

"""Deque is a "double ended queue": once it hits 100 items, if you append a 101st item to the right side, it automatically drops the oldest item from the left side. This makes it the perfect tool for tracking the average score of the last 100 episodes without having to manually delete old scores every loop."""

cartpole_hyperparameters = {
    "h_size": 16,
    "n_training_episodes": 1000,
    "n_evaluation_episodes": 10,
    "max_t": 1000,
    "gamma": 1.0,
    "lr": 1e-2,
    "env_id": "CartPole-v1",
    "state_space": obs_space.shape[0],
    "action_space": act_space.n,
}

cartpole_policy = Policy(
    cartpole_hyperparameters["state_space"],
    cartpole_hyperparameters["action_space"],
    cartpole_hyperparameters["h_size"],
).to("cuda")
cartpole_optimizer = optim.Adam(cartpole_policy.parameters(), lr=cartpole_hyperparameters["lr"])

scores = reinforce(
    cartpole_policy,
    cartpole_optimizer,
    cartpole_hyperparameters["n_training_episodes"],
    cartpole_hyperparameters["max_t"],
    cartpole_hyperparameters["gamma"],
    100,
)

