from gym.wrappers import TimeLimit


def record_agent(policy, env_id="CartPole-v1", max_t=2000):
    env = gym.make(env_id)
    env = TimeLimit(env.unwrapped, max_episode_steps=max_t)
    env = gym.wrappers.RecordVideo(env, "video", episode_trigger=lambda e: True)

    state = env.reset()
    for _ in range(max_t):
        action, _ = policy.act(state)
        state, reward, done, info = env.step(action)
        if done:
            break
    env.close()

